if(data){ var _imgs=[]; if(data.feature) _imgs.push(data.feature); ['breaches','policy','capability','regional','actors'].forEach(function(k){ if(Array.isArray(data[k])) _imgs=_imgs.concat(data[k]); }); for(var _ii=0;_ii<_imgs.length;_ii++){ await embedImg.call(this,_imgs[_ii]); } }
